const qdrantResponse = $('Scroll Qdrant').first().json;
const points = qdrantResponse.result?.points || [];

if (points.length === 0) {
  return [{ json: { response: 'No Kubernetes resources found in the vector database.' } }];
}

// Group by kind, then by namespace
const byKind = {};
for (const p of points) {
  const m = p.payload?.metadata || {};
  const kind = m.kind || '?';
  if (!byKind[kind]) byKind[kind] = [];
  byKind[kind].push({
    name: m.name || '?',
    namespace: m.namespace || 'cluster-scoped',
    spec: m.spec_summary || '-'
  });
}

// Build structured inventory text
const lines = [];
lines.push(`CLUSTER INVENTORY — ${points.length} resources total`);
lines.push('');

for (const [kind, items] of Object.entries(byKind).sort()) {
  // Group by namespace within each kind
  const byNs = {};
  for (const item of items) {
    if (!byNs[item.namespace]) byNs[item.namespace] = [];
    byNs[item.namespace].push(item.name);
  }
  lines.push(`${kind} (${items.length} total):`);
  for (const [ns, names] of Object.entries(byNs).sort()) {
    lines.push(`  ${ns} (${names.length}): ${names.join(', ')}`);
  }
}

return [{ json: { response: lines.join('\n') } }];
